module div_16bit(
    input  [15:0] A,
    input  [7:0]  B,
    output [15:0] result,
    output [15:0] odd
);

    reg [15:0] a_reg;
    reg [7:0]  b_reg;
    reg [15:0] result_reg;
    reg [15:0] odd_reg;

    assign result = result_reg;
    assign odd    = odd_reg;

    // First always block: latch inputs into registers
    always @(*) begin
        a_reg = A;
        b_reg = B;
    end

    // Second always block: combinational long division
    // Processes 9 steps to produce a 9-bit quotient (bits [8:0])
    // and an 8-bit remainder, both zero-extended to 16 bits
    always @(*) begin
        reg [7:0] partial;  // current partial dividend (8 bits, matches divisor width)
        reg [7:0] diff;     // subtraction result
        reg [8:0] quotient; // 9-bit quotient (16-bit / 8-bit can yield up to 9 bits)
        integer   i;

        partial  = a_reg[15:8]; // seed with top 8 bits of dividend
        diff     = 8'b0;
        quotient = 9'b0;

        // Iterate from quotient bit 8 down to 0 (9 steps total)
        for (i = 8; i >= 0; i = i - 1) begin
            if (partial >= b_reg) begin
                quotient[i] = 1'b1;
                diff        = partial - b_reg;
            end else begin
                quotient[i] = 1'b0;
                diff        = partial;
            end

            // Shift remainder left and bring in next dividend bit
            if (i > 0) begin
                partial = {diff[6:0], a_reg[i-1]};
            end
        end

        result_reg = {7'b0, quotient}; // zero-extend 9-bit quotient to 16 bits
        odd_reg    = {8'b0, diff};     // zero-extend 8-bit remainder to 16 bits
    end

endmodule

