module sequence_detector(
    input clk,
    input reset_n,
    input data_in,
    output sequence_detected,
    output IDLE,
    output S1,
    output S2,
    output S3,
    output S4
);

    // State encoding
    localparam STATE_IDLE = 3'd0;
    localparam STATE_S1   = 3'd1;
    localparam STATE_S2   = 3'd2;
    localparam STATE_S3   = 3'd3;
    localparam STATE_S4   = 3'd4;

    reg [2:0] current_state, next_state;

    always @(posedge clk or negedge reset_n) begin
        if (!reset_n)
            current_state <= STATE_IDLE;
        else
            current_state <= next_state;
    end

    always @(*) begin
        case (current_state)
            STATE_IDLE: next_state = data_in ? STATE_S1   : STATE_IDLE;
            STATE_S1:   next_state = data_in ? STATE_S1   : STATE_S2;
            STATE_S2:   next_state = data_in ? STATE_S1   : STATE_S3;
            STATE_S3:   next_state = data_in ? STATE_S4   : STATE_IDLE;
            STATE_S4:   next_state = data_in ? STATE_S1   : STATE_S2;
            default:    next_state = STATE_IDLE;
        endcase
    end

    assign sequence_detected = (current_state == STATE_S4);
    assign IDLE              = (current_state == STATE_IDLE);
    assign S1                = (current_state == STATE_S1);
    assign S2                = (current_state == STATE_S2);
    assign S3                = (current_state == STATE_S3);
    assign S4                = (current_state == STATE_S4);

endmodule
