module freq_divbyfrac(
    input clk,
    input rst_n,
    output clk_div
);

parameter MUL2_DIV_CLK = 7;

reg [2:0] cnt;
reg clk_pos, clk_neg;

// Counter + positive-edge divided clock
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        cnt     <= 3'd0;
        clk_pos <= 1'b1;
    end else begin
        if (cnt == MUL2_DIV_CLK - 1) begin
            cnt     <= 3'd0;
            clk_pos <= 1'b1;
        end else begin
            cnt <= cnt + 1'b1;
            if (cnt == (MUL2_DIV_CLK / 2 - 1))  // cnt == 2: next is 3, go low
                clk_pos <= 1'b0;
        end
    end
end

// Negative-edge divided clock (half-period phase shift)
always @(negedge clk or negedge rst_n) begin
    if (!rst_n)
        clk_neg <= 1'b0;
    else
        clk_neg <= (cnt < MUL2_DIV_CLK / 2) ? 1'b1 : 1'b0;
end

// OR the two phases to produce uniform 3.5x divided clock
assign clk_div = clk_pos | clk_neg;

endmodule

