module freq_divbyfrac(
    input clk,
    input rst_n,
    output clk_div
);

parameter MUL2_DIV_CLK = 7;

reg [2:0] cnt_pos;
reg [2:0] cnt_neg;
reg clk_div1;
reg clk_div2;

// Positive edge counter (0 to 6)
always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
        cnt_pos <= 3'd0;
    else if (cnt_pos == MUL2_DIV_CLK - 1)
        cnt_pos <= 3'd0;
    else
        cnt_pos <= cnt_pos + 1'b1;
end

// Negative edge counter (0 to 6, shifted by half input clock)
always @(negedge clk or negedge rst_n) begin
    if (!rst_n)
        cnt_neg <= 3'd0;
    else if (cnt_neg == MUL2_DIV_CLK - 1)
        cnt_neg <= 3'd0;
    else
        cnt_neg <= cnt_neg + 1'b1;
end

// clk_div1: posedge-based, high for floor(7/2)=3 cycles, low for 4 cycles
// Rises when cnt_pos wraps (was 6), falls when cnt_pos was 2 (next=3)
always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
        clk_div1 <= 1'b0;
    else if (cnt_pos == MUL2_DIV_CLK - 1)       // cnt=6 -> next cnt=0, go high
        clk_div1 <= 1'b1;
    else if (cnt_pos == MUL2_DIV_CLK / 2 - 1)   // cnt=2 -> next cnt=3, go low
        clk_div1 <= 1'b0;
end

// clk_div2: negedge-based, same pattern shifted by half input clock period
always @(negedge clk or negedge rst_n) begin
    if (!rst_n)
        clk_div2 <= 1'b0;
    else if (cnt_neg == MUL2_DIV_CLK - 1)
        clk_div2 <= 1'b1;
    else if (cnt_neg == MUL2_DIV_CLK / 2 - 1)
        clk_div2 <= 1'b0;
end

// OR the two phase-shifted clocks to produce uniform 50% duty cycle output
// clk_div1 high: t=0..3.0,  clk_div2 high: t=0.5..3.5
// OR result high: t=0..3.5, low: t=3.5..7.0  => period=7, duty=50%
assign clk_div = clk_div1 | clk_div2;

endmodule

